String portableSegment(String input) {
  final replaced = input.replaceAll(RegExp(r'[<>:"/\\|?*\x00-\x1f]'), '_');
  final cleaned = replaced.trim();
  return cleaned.isEmpty ? 'untitled' : cleaned;
}

