import 'export_name.dart';

class ReportBundle {
  final Set<String> _usedEntries = <String>{};

  String allocateEntry(String folder, String title) {
    final safeFolder = portableSegment(folder);
    final safeTitle = portableSegment(title);
    final stem = '$safeFolder/$safeTitle';

    var candidate = '$stem.txt';
    var suffix = 2;
    while (_usedEntries.contains(candidate)) {
      candidate = '$stem ($suffix).txt';
      suffix += 1;
    }
    _usedEntries.add(candidate);
    return candidate;
  }
}

