import '../lib/export_name.dart';
import '../lib/report_bundle.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

void main() {
  check(portableSegment('Quarter 1') == 'Quarter 1', 'keeps readable names');
  check(portableSegment('ops/east') == 'ops_east', 'replaces separators');
  check(
    portableSegment('   ') == 'untitled',
    'supplies an empty-name fallback',
  );

  final bundle = ReportBundle();
  check(
    bundle.allocateEntry('Support', 'Summary') == 'Support/Summary.txt',
    'allocates the first entry',
  );
  check(
    bundle.allocateEntry('Support', 'Summary') == 'Support/Summary (2).txt',
    'adds a deterministic suffix for an exact duplicate',
  );

  print('public tests passed');
}
